pythonCopierModifier"""
:file_type: class
:file_name: base_connection.py
:description: Classe mère pour les connexions à la base de données (temporaire ou persistante).
"""

import os
from sqlalchemy import create_engine, text
from sqlalchemy.orm import sessionmaker
from Organismus.Corpus.Mesoderma.Ossa_Structura.actions.get_database_path import get_database_path
from Organismus.Corpus.Mesoderma.Ossa_Structura.actions.log import log

class BaseConnection:
    def __init__(self, db_path=None):
        self.db_path = db_path or get_database_path().get("data")
        self.engine = None
        self.session = None
        self.connected = False

    def connect(self):
        try:
            self.engine = create_engine(f"sqlite:///{self.db_path}", echo=False)
            self.connected = True
            log("✅ Connexion à la base établie.", "INFO")
            return {"result": True, "data": self.engine, "message": "Connexion réussie"}
        except Exception as e:
            log(f"❌ Erreur de connexion : {e}", "ERROR")
            return {"result": False, "data": None, "message": str(e)}

    def get_session(self):
        if not self.connected:
            self.connect()
        if self.engine:
            Session = sessionmaker(bind=self.engine)
            self.session = Session()
            log("✅ Session SQLAlchemy créée.", "DEBUG")
            return {"result": True, "data": self.session, "message": "Session créée"}
        return {"result": False, "data": None, "message": "Session impossible sans engine"}

    def execute(self, query: str):
        if not self.connected:
            self.connect()
        if self.engine:
            try:
                with self.engine.connect() as conn:
                    result = conn.execute(text(query))
                    log(f"✅ Requête exécutée : {query}", "INFO")
                    return {"result": True, "data": result, "message": "Requête exécutée"}
            except Exception as e:
                log(f"❌ Échec de requête : {e}", "ERROR")
                return {"result": False, "data": None, "message": str(e)}
        return {"result": False, "data": None, "message": "Engine non initialisé"}


✅ Avantages


Toutes les bases partagées sont prêtes dans BaseConnection


Les classes filles peuvent :


appeler les méthodes telles quelles


ou surcharger (par exemple un cache, ou session durable)





