import os
import json
from superquery import Query
from Organismus.Praeorganismus.Truncus_Fundamentalis.actions.get_project_root import get_project_root

def create_initial_objects():
    base_path = get_project_root()
    json_path = os.path.join(base_path, "projects", "default_core", "resources", "tables_data.json")

    if not os.path.exists(json_path):
        print(f"[ERROR] Fichier JSON introuvable à : {json_path}")
        return

    with open(json_path, "r") as f:
        data = json.load(f)

    q = Query()

    for table, records in data.items():
        if isinstance(records, list) and records:
            print(f"[INFO] Insertion de {len(records)} enregistrements dans '{table}'...")
            q.bdd_add_records(table, records)
        else:
            print(f"[WARN] Aucune donnée à insérer pour '{table}'.")

    print("[SUCCESS] Données initiales insérées avec succès.")


